package cli

import (
	"fmt"

	"github.com/spf13/cobra"
)

var version = "2026.7.1"

// Persistent flags shared by every subcommand. Empty strings/zero values
// indicate "fall back to defaults" (see store.DefaultDBPath, etc.).
var (
	flagDBPath string
	flagJSON   bool
	flagSelect string
)

// RootCmd builds the Cobra root command tree. Exposed separately from
// Execute so the MCP server (internal/mcp) can walk the tree without
// running it.
func RootCmd() *cobra.Command {
	rootCmd := &cobra.Command{
		Use:          "airframe-pp-cli",
		Short:        "Aircraft forensics from open public records — tail-number dossiers, fleet research, model-level safety, and NTSB event archaeology.",
		SilenceUsage: true,
		Version:      version,
	}
	rootCmd.SetVersionTemplate("airframe-pp-cli {{ .Version }}\n")

	rootCmd.PersistentFlags().StringVar(&flagDBPath, "db-path", "", "Path to the local SQLite store (default: ~/.local/share/airframe-pp-cli/data.db)")
	rootCmd.PersistentFlags().BoolVar(&flagJSON, "json", false, "Emit JSON output instead of human-readable text")
	rootCmd.PersistentFlags().StringVar(&flagSelect, "select", "", "Return only the dotted-path subtree of the JSON envelope (e.g., results.aircraft.owner_name). Implies --json.")

	rootCmd.AddCommand(newSyncCmd())
	rootCmd.AddCommand(newTailCmd())
	rootCmd.AddCommand(newOwnerCmd())
	rootCmd.AddCommand(newModelCmd())
	rootCmd.AddCommand(newFlightCmd())
	rootCmd.AddCommand(newEventCmd())
	rootCmd.AddCommand(newSearchCmd())
	rootCmd.AddCommand(newDoctorCmd())
	rootCmd.AddCommand(newVersionCliCmd())

	return rootCmd
}

// Execute runs the CLI.
func Execute() error {
	return RootCmd().Execute()
}

// ExitCode extracts a process exit code from an error returned by Execute.
func ExitCode(err error) int {
	if err == nil {
		return 0
	}
	return 1
}

func newVersionCliCmd() *cobra.Command {
	return &cobra.Command{
		Use:   "version",
		Short: "Print version",
		Run: func(cmd *cobra.Command, args []string) {
			fmt.Printf("airframe-pp-cli %s\n", version)
		},
	}
}
